import json
import logging
from datetime import datetime
from pathlib import Path

from models import AmbiguousNormalization, EmailMatch, InvoiceResult, SearchRule, Transaction

logger = logging.getLogger(__name__)


class RunArtifacts:
    """Persists intermediate pipeline stage outputs to a per-run directory."""

    def __init__(self, run_dir: Path, statement_path: str) -> None:
        self.run_dir = run_dir
        run_dir.mkdir(parents=True, exist_ok=True)
        self._write("meta.json", {
            "timestamp": run_dir.name,
            "statement_path": statement_path,
            "month": None,
        })

    def save_meta(self, month: str) -> None:
        self._write("meta.json", {
            "timestamp": self.run_dir.name,
            "month": month,
        })

    def save_stage1(
        self,
        transactions: list[Transaction],
        ambiguous: list[AmbiguousNormalization],
    ) -> None:
        self._write_models("01_transactions.json", transactions)
        self._write_models("01_ambiguous.json", ambiguous)

    def save_stage2(self, rules: list[SearchRule]) -> None:
        self._write_models("02_rules.json", rules)

    def save_stage3(self, emails: list[EmailMatch]) -> None:
        self._write_models("03_emails.json", emails)

    def save_stage4(self, readings: list[dict]) -> None:
        self._write("04_readings.json", readings)

    def save_stage5(self, results: list[InvoiceResult]) -> None:
        self._write_models("05_results.json", results)

    def _write_models(self, filename: str, models: list) -> None:
        self._write(filename, [m.model_dump(mode="json") for m in models])

    def _write(self, filename: str, data: object) -> None:
        try:
            (self.run_dir / filename).write_text(
                json.dumps(data, indent=2, default=str),
                encoding="utf-8",
            )
        except Exception:
            logger.warning("Failed to write artifact %s", filename, exc_info=True)

